 92→export function App() {
 93→  const [query, setQuery] = useState('');
 94→  const [selectedIndex, setSelectedIndex] = useState(0);
 95→  const [actionsOpen, setActionsOpen] = useState(false);
 96→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
 97→
 98→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
 99→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
100→  const selectedItem = drilledItem ?? allItems[selectedIndex];
101→
102→  const handleQueryChange = useCallback((value: string) => {
103→    setQuery(value);
104→    setSelectedIndex(0);
105→    setActionsOpen(false);
106→  }, []);
107→
108→  const handleActiveIndexChange = useCallback((index: number) => {
109→    setSelectedIndex(index);
110→    setActionsOpen(false);
111→  }, []);
112→
113→  const handleDrillIn = useCallback(() => {
114→    const item = allItems[selectedIndex];
115→    if (item) {
116→      setDrilledItem(item);
117→      setQuery('');
118→      setActionsOpen(false);
119→    }
120→  }, [
121→    allItems,
122→    selectedIndex,
123→  ]);
124→
125→  const handleDrillBack = useCallback(() => {
126→    setDrilledItem(null);
127→    setQuery('');
128→    setSelectedIndex(0);
129→    setActionsOpen(false);
130→  }, []);
131→
132→  const breadcrumbs: BreadcrumbItem[] | undefined = drilledItem
133→    ? [
134→        {
135→          label: 'Raycast',
136→          onBack: handleDrillBack,
137→        },
138→        {
139→          label: drilledItem.title,
140→        },
141→      ]
142→    : undefined;
143→
144→  const toggleActions = useCallback(() => {
145→    setActionsOpen(prev => !prev);
146→  }, []);
147→
148→  const closeActions = useCallback(() => {
149→    setActionsOpen(false);
150→  }, []);
151→
152→  useEffect(() => {
153→    function handleKeyDown(e: KeyboardEvent) {
154→      if (e.key === 'k' && e.metaKey) {
155→        e.preventDefault();
156→        setActionsOpen(prev => !prev);
157→      }
158→    }
159→
160→    window.addEventListener('keydown', handleKeyDown);
161→    return () => window.removeEventListener('keydown', handleKeyDown);
162→  }, []);
163→
164→  const detail = selectedItem?.detail;
165→
166→  const dropdownActions = useMemo(
167→    () => [
168→      {
169→        label: 'Open',
170→        shortcut: <Kbd keys={['↵']} />,
171→      },
172→      {
173→        label: 'Copy Name',
174→        shortcut: (
175→          <Kbd
176→            keys={[
177→              '⌘',
178→              'C',
179→            ]}
180→          />
181→        ),
182→      },
183→      {
184→        label: 'Show Detail',
185→        shortcut: (
186→          <Kbd
187→            keys={[
188→              '⌘',
189→              'D',
190→            ]}
191→          />
192→        ),
193→      },
194→      {
195→        label: 'Pin to Top',
196→        shortcut: (
197→          <Kbd
198→            keys={[
199→              '⌘',
200→              'P',
201→            ]}
202→          />
203→        ),
204→      },
205→    ],
206→    [],
207→  );
208→
209→  return (
210→    <CommandPalette isLoading>
211→      <SearchBar
212→        value={query}
213→        onChange={handleQueryChange}
214→        activeDescendantId={
215→          allItems.length > 0 ? `list-item-${selectedIndex}` : undefined
216→        }
217→        breadcrumbs={breadcrumbs}
218→      />
219→      <div
220→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
221→      >
222→        <div className="command-palette__list-container">
223→          {allItems.length === 0 ? (
224→            <EmptyState
225→              icon={<SearchIcon />}
226→              title="No Results"
227→              description="Try a different search term"
228→            />
229→          ) : (
230→            <List
231→              itemCount={allItems.length}
232→              onActiveIndexChange={handleActiveIndexChange}
233→              onAction={handleDrillIn}
234→            >
235→              {(() => {
236→                let globalIndex = 0;
237→                return filtered.map(section => (
238→                  <ListSection key={section.title} title={section.title}>
239→                    {section.items.map(item => {
240→                      const idx = globalIndex++;
241→                      return (
242→                        <ListItem
243→                          key={item.id}
244→                          index={idx}
245→                          title={item.title}
246→                          subtitle={item.subtitle}
247→                          icon={item.icon}
248→                          accessories={item.accessories}
249→                        />
250→                      );
251→                    })}
252→                  </ListSection>
253→                ));
254→              })()}
255→            </List>
256→          )}
257→        </div>
258→        {detail && (
259→          <Detail
260→            markdown={detail.markdown}
261→            metadata={
262→              detail.metadata ? (
263→                <DetailMetadata>
264→                  {detail.metadata.map(renderMetadataEntry)}
265→                </DetailMetadata>
266→              ) : undefined
267→            }
268→          />
269→        )}
270→      </div>
271→      <ActionPanel
272→        actions={[
273→          {
274→            label: 'Open',
275→            shortcut: <Kbd keys={['↵']} />,
276→          },
277→          {
278→            label: 'Actions',
279→            shortcut: (
280→              <Kbd
281→                keys={[
282→                  '⌘',
283→                  'K',
284→                ]}
285→              />
286→            ),
287→            onClick: toggleActions,
288→          },
289→        ]}
290→        dropdownOpen={actionsOpen}
291→        dropdownActions={dropdownActions}
292→        onDropdownClose={closeActions}
293→      />
294→    </CommandPalette>
295→  );
296→}
